import com.liferay.jenkins.results.parser.JenkinsResultsParserUtil;

import java.util.regex.Matcher;
import java.util.regex.Pattern;

import org.yaml.snakeyaml.Yaml;

Pattern hostnamePattern = Pattern.compile("(cloud-[^\\.]+|test-\\d+-\\d+-\\d+)(\\.lax\\.liferay\\.com)?");

public Map getNetworksMap() {
	String hostname = project.getProperty("env.HOSTNAME");

	if (JenkinsResultsParserUtil.isNullOrEmpty(hostname)) {
		return null;
	}

	Matcher hostnameMatcher = hostnamePattern.matcher(hostname);

	if (!hostnameMatcher.find()) {
		return null;
	}

	Map externalMap = new HashMap();

	externalMap.put("name", hostnameMatcher.group(1));

	Map defaultMap = new HashMap();

	defaultMap.put("external", externalMap);

	Map networksMap = new HashMap();

	networksMap.put("default", defaultMap);

	return networksMap;
}

Yaml yaml = new Yaml();

Map map = yaml.load(new FileInputStream(new File(project.getProperty("analytics.cloud.asah.dir"), "@{docker.compose.file.name}")));

List dockerComposeImageNames = new ArrayList();

for (String key : map.keySet()) {
	if (!key.equals("services")) {
		continue;
	}

	Object servicesMapObject = map.get(key);

	if (!(servicesMapObject instanceof Map)) {
		continue;
	}

	Map servicesMap = (Map)servicesMapObject;

	for (String serviceName : servicesMap.keySet()) {
		Object serviceObject = servicesMap.get(serviceName);

		if (!(serviceObject instanceof Map)) {
			continue;
		}

		Map serviceMap = (Map)serviceObject;

		String dockerComposeImageName = "com-liferay-osb-asah-private-" + serviceName;

		if (!Objects.equals("@{docker.compose.run}", "true")) {
			serviceMap.remove("build");

			if (!serviceMap.containsKey("image")) {
				serviceMap.put("image", dockerComposeImageName + ":latest");
			}
		}

		dockerComposeImageNames.add(dockerComposeImageName);

		List ports = new ArrayList();

		Object portsObject = serviceMap.get("ports");

		if (portsObject instanceof List) {
			ports.addAll((List)portsObject);
		}

		if (serviceName.equals("osbasahupgrade")) {
			ports.add(project.getProperty("analytics.cloud.asah.upgrade.port") + ":8080");

			serviceMap.put("image", project.getProperty("analytics.cloud.faro.image.name") + ":latest");

			dockerComposeImageNames.add(project.getProperty("analytics.cloud.faro.image.name"));
		}
		else if (serviceName.equals("osbfarofrontend")) {
			ports.remove("8080:8080");
			ports.remove("11311:11311");

			ports.add(project.getProperty("analytics.cloud.faro.dxp.port") + ":8080");
			ports.add(project.getProperty("analytics.cloud.faro.osgi.console.port") + ":11311");
		}
		else if (serviceName.equals("test_elasticsearch")) {
			ports.remove("9200:9200");

			ports.add(project.getProperty("analytics.cloud.asah.elasticsearch.port") + ":9200");
		}

		serviceMap.put("ports", ports);
	}
}

Map networksMap = getNetworksMap();

if (networksMap != null) {
	map.put("networks", networksMap);
}

File dockerComposeFile = new File(project.getProperty("docker.compose.file.path"));

PrintWriter printWriter = new PrintWriter(dockerComposeFile);

yaml.dump(map, printWriter);

project.setProperty("docker.compose.file.path", JenkinsResultsParserUtil.getCanonicalPath(dockerComposeFile));
project.setProperty("docker.compose.image.names", JenkinsResultsParserUtil.join(",", dockerComposeImageNames));


import com.liferay.jenkins.results.parser.JenkinsResultsParserUtil;

import java.util.regex.Matcher;
import java.util.regex.Pattern;

import org.yaml.snakeyaml.Yaml;

Pattern dockerImageUserPattern = Pattern.compile("def dockerImageUser = \"([^\"]+)\"");
Pattern dockerImageIdPattern = Pattern.compile("def dockerImageId = \"([^\"]+)\"");

public String getFaroImageName() {
	File faroBuildGradleFile = new File(project.getProperty("analytics.cloud.faro.dir"), "build-ext.gradle");

	if (!faroBuildGradleFile.exists()) {
		faroBuildGradleFile = new File(project.getProperty("analytics.cloud.faro.dir"), "build.gradle");
	}

	String content = JenkinsResultsParserUtil.read(faroBuildGradleFile);

	String dockerImageUser = null;

	Matcher dockerImageUserMatcher = dockerImageUserPattern.matcher(content);

	if (dockerImageUserMatcher.find()) {
		dockerImageUser = dockerImageUserMatcher.group(1);
	}

	String dockerImageId = null;

	Matcher dockerImageIdMatcher = dockerImageIdPattern.matcher(content);

	if (dockerImageIdMatcher.find()) {
		dockerImageId = dockerImageIdMatcher.group(1);
	}

	if (JenkinsResultsParserUtil.isNullOrEmpty(dockerImageUser)) {
		return dockerImageId;
	}

	return dockerImageUser + "/" + dockerImageId;
}

project.setProperty("analytics.cloud.faro.image.name", getFaroImageName());


import com.liferay.jenkins.results.parser.JenkinsResultsParserUtil;

import java.util.regex.Matcher;
import java.util.regex.Pattern;

public static List getContainerNames() {
	File dockerComposeFile = new File(project.getProperty("docker.compose.file.path"));

	if (!dockerComposeFile.exists()) {
		return new ArrayList();
	}

	List containerNames = new ArrayList();

	String content = JenkinsResultsParserUtil.read(dockerComposeFile);

	Pattern pattern = Pattern.compile("container_name: (.*)");

	Matcher matcher = pattern.matcher(content);

	while (matcher.find()) {
		containerNames.add(matcher.group(1));
	}

	return containerNames;
}

project.setProperty("container.names", JenkinsResultsParserUtil.join(",", getContainerNames()))


public int getRetryCount() {
	String retryCount = project.getProperty("analytics.cloud.retry.count");

	if (retryCount.matches("\\d+")) {
		return Integer.valueOf(retryCount);
	}

	return 3;
}

for (int i = 0; i < getRetryCount(); i++) {
	String containerFileName = "@{container.name}.log";

	if (i > 0) {
		containerFileName = "@{container.name}." + i + ".log";
	}

	File containerFile = new File(project.getProperty("docker.logs.dir"), containerFileName);

	if (containerFile.exists()) {
		continue;
	}

	project.setProperty("container.file.name", containerFileName);

	break;
}

